    System.out.println("Взята проба грунта №" + sampleCount);
    if (sampleCount >= 3) {
        dangerDetected = false;
    }
} while (dangerDetected);
System.out.println("Сбор проб завершён. Всего взято: " + sampleCount + " проб.");

